ucs.kql:
let aviationLures = dynamic(["invoice","cargo","charter","flight","aviation","boeing","airbus","aircraft","quotation","rfq","manifest","airway","shipment","freight","trip","itinerary"]);
let cloudHosts = dynamic(["drive.google.com","docs.google.com","onedrive.live.com","1drv.ms","cdn.discordapp.com","mediafire.com","raw.githubusercontent.com","pastebin.com","transfer.sh","anonfiles.com"]);
let ddnsHosts = dynamic([".duckdns.org",".hopto.org",".ddns.net",".no-ip.com",".ydns.eu",".linkpc.net",".sytes.net",".zapto.org"]);
let stage1 =
DeviceProcessEvents
| where Timestamp > ago(14d)
| where FileName in~ ("wscript.exe","cscript.exe","mshta.exe","powershell.exe","pwsh.exe")
| where InitiatingProcessFileName in~ ("outlook.exe","chrome.exe","msedge.exe","firefox.exe","winrar.exe","7zg.exe","explorer.exe")
| where ProcessCommandLine has_any (cloudHosts) or ProcessCommandLine has_any (aviationLures) or ProcessCommandLine has_any (".vbs",".hta",".lnk",".js")
| project Stage1Time=Timestamp, DeviceId, DeviceName, AccountName, ParentProc=InitiatingProcessFileName, ScriptHost=FileName, Stage1Cmd=ProcessCommandLine;
let stage2 =
DeviceNetworkEvents
| where Timestamp > ago(14d)
| where RemoteUrl has_any (ddnsHosts) or RemoteUrl has_any (cloudHosts)
| project Stage2Time=Timestamp, DeviceId, RemoteUrl, RemoteIP, RemotePort, NetInitiator=InitiatingProcessFileName;
stage1
| join kind=inner stage2 on DeviceId
| where Stage2Time between (Stage1Time .. Stage1Time + 10m)
| extend EmailLure = tostring(extract(@"(invoice|cargo|charter|flight|aviation|boeing|airbus|aircraft|quotation|rfq|manifest)", 1, tolower(Stage1Cmd)))
| join kind=leftouter (EmailEvents | where Timestamp > ago(14d) | where Subject has_any (aviationLures) | project EmailTime=Timestamp, RecipientEmailAddress, SenderFromAddress, Subject, NetworkMessageId) on $left.AccountName == $right.RecipientEmailAddress
| project Stage1Time, DeviceName, AccountName, ParentProc, ScriptHost, Stage1Cmd, RemoteUrl, RemoteIP, NetInitiator, SenderFromAddress, Subject
| order by Stage1Time desc

let dotnetHosts = dynamic(["RegSvcs.exe","RegAsm.exe","InstallUtil.exe","AspNetCompiler.exe","aspnet_compiler.exe","MSBuild.exe","jsc.exe","vbc.exe","csc.exe"]);
let scriptParents = dynamic(["wscript.exe","cscript.exe","mshta.exe","powershell.exe","pwsh.exe","cmd.exe","explorer.exe"]);
let ddnsHosts = dynamic([".duckdns.org",".hopto.org",".ddns.net",".no-ip.com",".sytes.net",".zapto.org",".linkpc.net",".myftp.org",".ydns.eu"]);
let ratPorts = dynamic([1604,1177,2404,4404,5552,6606,7707,8808,2000,5000,8080,4444]);
let hollowed =
DeviceProcessEvents
| where Timestamp > ago(7d)
| where FileName in~ (dotnetHosts)
| where InitiatingProcessFileName in~ (scriptParents)
| where FolderPath !startswith "C:\\Windows\\Microsoft.NET\\" or InitiatingProcessFileName !in~ ("devenv.exe","msdeploy.exe")
| project SuspectTime=Timestamp, DeviceId, DeviceName, AccountName, Parent=InitiatingProcessFileName, ParentCmd=InitiatingProcessCommandLine, Hollowed=FileName, HollowedCmd=ProcessCommandLine, HollowedPid=ProcessId;
let beacon =
DeviceNetworkEvents
| where Timestamp > ago(7d)
| where RemoteUrl has_any (ddnsHosts) or RemoteIPType == "Public"
| where RemotePort in (ratPorts) or RemoteUrl has_any (ddnsHosts)
| project NetTime=Timestamp, DeviceId, InitProc=InitiatingProcessFileName, InitPid=InitiatingProcessId, RemoteUrl, RemoteIP, RemotePort;
let persistence =
DeviceRegistryEvents
| where Timestamp > ago(7d)
| where RegistryKey has_any (@"\CurrentVersion\Run", @"\CurrentVersion\RunOnce")
| project RegTime=Timestamp, DeviceId, RegistryValueName, RegistryValueData, RegInit=InitiatingProcessFileName;
hollowed
| join kind=inner beacon on DeviceId
| where NetTime between (SuspectTime .. SuspectTime + 15m)
| where InitProc =~ Hollowed or InitPid == HollowedPid
| join kind=leftouter persistence on DeviceId
| project SuspectTime, DeviceName, AccountName, Parent, ParentCmd, Hollowed, HollowedCmd, RemoteUrl, RemoteIP, RemotePort, RegistryValueName, RegistryValueData
| order by SuspectTime desc
